.power-up-btn {
    width: clamp(60px, 20vw, 120px);
    height: clamp(60px, 20vw, 120px);
    border-radius: 24px;
    border: 4px solid #000;
    background: #141414;
    color: white;
    font-size: clamp(16px, 8vw, 50px);
    cursor: pointer;
    backdrop-filter: blur(10px);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    position: relative;
}

.power-up-label {
    font-size: clamp(8px, 2.5vw, 14px);
    color: #aaa;
    margin-top: -2px;
    line-height: 1;
    font-weight: 600;
    letter-spacing: 0.02em;
}

.power-up-btn.disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* Locked power-up styling */
.power-up-btn.locked {
    opacity: 0;
    filter: grayscale(100%);
    cursor: not-allowed;
    position: relative;
    display: none;
}

.power-up-btn.active {
    background: #aee96b;
    box-shadow: 0 -6px 0 0 rgba(0, 0, 0, 0.25) inset;
}

/* Power-up use indicator */
.use-indicator {
    position: absolute;
    top: -10%;
    right: -10%;
    width: clamp(26px, 8vw, 50px);
    height: clamp(26px, 8vw, 50px);
    background: #ff401a;
    box-shadow: 0 -0.5vw 0 0 rgba(0, 0, 0, 0.25) inset;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    /* border: 2px solid #902009; */
    z-index: 10;

    color: #fff;
    /* text-shadow: -2px -2px 0 black, 2px -2px 0 black, -2px 2px 0 black, 2px 2px 0 black; */
    font-family: Nunito;
    font-size: 16px;
    font-weight: 900;

    &.transient-count {
        background: var(--tile-freeswap-badge-bg);
    }
}

.cost-indicator {
    position: absolute;
    top: -8px;
    right: -8px;
    display: flex;
    align-items: flex-start;
    gap: 0;
    z-index: 10;

